-- ============================================================================
-- Seed data: ~50 realistic Indian passenger cars across brands/segments.
--
-- NOT auto-executed on app startup: the datasource is a real, persistent
-- MySQL instance (not embedded), and Spring Boot only auto-runs data.sql
-- for embedded databases unless spring.sql.init.mode=always is set (it is
-- deliberately NOT set here). Run this manually once against the schema
-- after Hibernate (ddl-auto=update) has created the tables, e.g.:
--   mysql -h <host> -P <port> -u <user> -p<password> <database> < data.sql
--
-- Safe to re-run: truncates seed tables first (also resets AUTO_INCREMENT).
-- ============================================================================

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE car_pros;
TRUNCATE TABLE car_cons;
TRUNCATE TABLE cars;
SET FOREIGN_KEY_CHECKS = 1;



